public void testZeroStandardDeviation() throws Exception {
    NormalDistribution distribution = (NormalDistribution) getDistribution();
    distribution.setMean(5.0);
    distribution.setStandardDeviation(0.0);

    // Test value less than mean
    double lowerProb = distribution.cumulativeProbability(3.0);
    assertEquals(0.0, lowerProb, 0.0);

    // Test value greater than mean
    double upperProb = distribution.cumulativeProbability(7.0);
    assertEquals(1.0, upperProb, 0.0);

    // Test value equal to mean
    double equalProb = distribution.cumulativeProbability(5.0);
    assertEquals(0.5, equalProb, 0.0);
}

public void testNegativeMeanExtremeValues() throws Exception {
    NormalDistribution distribution = (NormalDistribution) getDistribution();
    distribution.setMean(-50.0);
    distribution.setStandardDeviation(10.0);

    // Test far left tail
    double leftTail = distribution.cumulativeProbability(-150.0);
    assertTrue(leftTail > 0.0);
    assertTrue(leftTail < 0.00001);

    // Test far right tail
    double rightTail = distribution.cumulativeProbability(50.0);
    assertTrue(rightTail < 1.0);
    assertTrue(rightTail > 0.99999);
}

public void testLargeStandardDeviation() throws Exception {
    NormalDistribution distribution = (NormalDistribution) getDistribution();
    distribution.setMean(0.0);
    distribution.setStandardDeviation(100.0);

    // With large std dev, values closer to mean should be near 0.5
    double prob10 = distribution.cumulativeProbability(10.0);
    assertTrue(prob10 > 0.5);
    assertTrue(prob10 < 0.6);

    double probNeg10 = distribution.cumulativeProbability(-10.0);
    assertTrue(probNeg10 < 0.5);
    assertTrue(probNeg10 > 0.4);
}
